import React from "react";
import { Bar, Line, Pie } from "react-chartjs-2";
import {
  Chart as ChartJS,
  BarElement,
  LineElement,
  ArcElement,
  CategoryScale,
  LinearScale,
  PointElement,
  Tooltip,
  Legend,
} from "chart.js";

ChartJS.register(
  BarElement,
  LineElement,
  ArcElement,
  CategoryScale,
  LinearScale,
  PointElement,
  Tooltip,
  Legend
);

const Charts = () => {

  // Dummy data (later replace with backend)
  const salaryByRole = {
    labels: ["Developer", "Data Scientist", "Tester"],
    datasets: [
      {
        label: "Salary",
        data: [40000, 60000, 30000],
        backgroundColor: ["#4facfe", "#00f2fe", "#43e97b"],
      },
    ],
  };

  const experienceData = {
    labels: [1, 2, 3, 4, 5],
    datasets: [
      {
        label: "Salary Growth",
        data: [20000, 30000, 45000, 60000, 80000],
        borderColor: "#4facfe",
        fill: false,
      },
    ],
  };

  const skillsData = {
    labels: ["Python", "Java", "ML", "Others"],
    datasets: [
      {
        data: [30, 25, 25, 20],
        backgroundColor: ["#667eea", "#764ba2", "#43e97b", "#f093fb"],
      },
    ],
  };

  return (
    <div style={{ padding: "20px" }}>
      
      <h2 style={{ textAlign: "center" }}>📊 Insights Dashboard</h2>

      <div style={{ display: "flex", gap: "20px", marginTop: "20px" }}>
        <div style={{ flex: 1 }}>
          <Bar data={salaryByRole} />
        </div>

        <div style={{ flex: 1 }}>
          <Line data={experienceData} />
        </div>
      </div>

      <div style={{ marginTop: "30px" }}>
        <Pie data={skillsData} />
      </div>

    </div>
  );
};

export default Charts;
